# AWS Auto Scaling for GPU inference fleet
# (Terraform snippet — illustrative)
resource "aws_autoscaling_group" "llm_inference" {
  name                = "llm-inference-asg"
  min_size            = 2        # always-on minimum
  max_size            = 20       # burst ceiling
  desired_capacity    = 4

  mixed_instances_policy {
    instances_distribution {
      on_demand_base_capacity                  = 2   # always on-demand
      on_demand_percentage_above_base_capacity = 0   # rest use spot
      spot_allocation_strategy                 = "capacity-optimized"
    }
    launch_template {
      launch_template_specification {
        launch_template_id = aws_launch_template.gpu.id
        version            = "$Latest"
      }
      override {
        instance_type = "g5.xlarge"   # A10G 24GB
      }
      override {
        instance_type = "p3.2xlarge"  # V100 16GB fallback
      }
    }
  }
}

resource "aws_autoscaling_policy" "scale_out" {
  name                   = "gpu-scale-out"
  autoscaling_group_name = aws_autoscaling_group.llm_inference.name
  policy_type            = "TargetTrackingScaling"
  target_tracking_configuration {
    predefined_metric_specification {
      predefined_metric_type = "ASGAverageCPUUtilization"
    }
    target_value = 60.0
  }
}
